import AppKit

/// The colored Claude logo used as the menu bar icon, embedded as a PNG so it
/// works both via `swift run` and from the bundled .app (no resource lookup).
enum MenuBarIcon {
    static let image: NSImage = {
        guard let data = Data(base64Encoded: base64, options: .ignoreUnknownCharacters),
              let img = NSImage(data: data) else { return NSImage() }
        img.size = NSSize(width: 18, height: 18)
        img.isTemplate = false // keep the terracotta color
        return img
    }()

    private static let base64 = ""
}
